import { forwardRef, useId } from 'react';
import { cn } from '../../../utils/cn';
import type { InputProps } from './Input.types';

const sizeClasses = {
  sm: 'h-8 text-xs px-3',
  md: 'h-10 text-sm px-3.5',
  lg: 'h-12 text-base px-4',
};

const variantClasses = {
  outline: 'border border-gray-200 rounded-xl bg-white focus:border-crisp-500 focus:ring-2 focus:ring-crisp-100',
  filled:  'border border-transparent rounded-xl bg-gray-100 focus:bg-white focus:border-crisp-500 focus:ring-2 focus:ring-crisp-100',
  flushed: 'border-b border-gray-200 rounded-none bg-transparent focus:border-crisp-500',
};

export const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      label,
      error,
      hint,
      leftAddon,
      rightAddon,
      inputSize = 'md',
      variant = 'outline',
      wrapperClassName,
      className,
      id: externalId,
      ...props
    },
    ref,
  ) => {
    const generatedId = useId();
    const id = externalId ?? generatedId;

    return (
      <div className={cn('flex flex-col gap-1.5', wrapperClassName)}>
        {label && (
          <label htmlFor={id} className="text-sm font-medium text-gray-700">
            {label}
            {props.required && <span className="text-rose-500 ml-1">*</span>}
          </label>
        )}
        <div className="relative flex items-center">
          {leftAddon && (
            <div className="absolute left-3 flex items-center text-gray-400 pointer-events-none">
              {leftAddon}
            </div>
          )}
          <input
            ref={ref}
            id={id}
            aria-invalid={!!error}
            aria-describedby={error ? `${id}-error` : hint ? `${id}-hint` : undefined}
            className={cn(
              'w-full outline-none transition-all duration-150 placeholder:text-gray-300 text-gray-800',
              sizeClasses[inputSize],
              variantClasses[variant],
              error && 'border-rose-400 focus:border-rose-400 focus:ring-rose-100',
              leftAddon && 'pl-9',
              rightAddon && 'pr-9',
              props.disabled && 'opacity-50 cursor-not-allowed',
              className,
            )}
            {...props}
          />
          {rightAddon && (
            <div className="absolute right-3 flex items-center text-gray-400">
              {rightAddon}
            </div>
          )}
        </div>
        {error && (
          <p id={`${id}-error`} className="text-xs text-rose-500 flex items-center gap-1">
            <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            {error}
          </p>
        )}
        {!error && hint && (
          <p id={`${id}-hint`} className="text-xs text-gray-400">
            {hint}
          </p>
        )}
      </div>
    );
  },
);

Input.displayName = 'Input';
